import os
import pymysql
import json
import re
from typing import Any


def get_db_connection():
    """Create a database connection using environment variables."""
    return pymysql.connect(
        host=os.environ.get('DB_HOST', '127.0.0.1'),
        user=os.environ.get('DB_USER'),
        password=os.environ.get('DB_PASSWORD'),
        database=os.environ.get('DB_NAME'),
        port=int(os.environ.get('DB_PORT', 3306)),
        charset='utf8mb4',
        cursorclass=pymysql.cursors.DictCursor,
        connect_timeout=10,
        read_timeout=10,
        write_timeout=10,
    )


# Allowlists for preventing injection via column/table names
ALLOWED_TABLES = {'products', 'users', 'orders', 'categories'}

ALLOWED_COLUMNS = {
    'products': {'id', 'name', 'description', 'price', 'category_id', 'created_at', 'status'},
    'users': {'id', 'username', 'email', 'created_at', 'status'},
    'orders': {'id', 'user_id', 'product_id', 'quantity', 'total', 'created_at', 'status'},
    'categories': {'id', 'name', 'description', 'created_at'},
}

ALLOWED_OPERATORS = {'=', '!=', '>', '<', '>=', '<=', 'LIKE', 'IN', 'IS NULL', 'IS NOT NULL'}

ALLOWED_SORT_DIRECTIONS = {'ASC', 'DESC'}

MAX_LIMIT = 100
DEFAULT_LIMIT = 20


def validate_table(table: str) -> str:
    """Validate table name against allowlist."""
    if table not in ALLOWED_TABLES:
        raise ValueError(f"Invalid table: {table}. Allowed tables: {ALLOWED_TABLES}")
    return table


def validate_column(table: str, column: str) -> str:
    """Validate column name against allowlist for the given table."""
    if table not in ALLOWED_COLUMNS:
        raise ValueError(f"Invalid table: {table}")
    if column not in ALLOWED_COLUMNS[table]:
        raise ValueError(f"Invalid column: {column}. Allowed columns for {table}: {ALLOWED_COLUMNS[table]}")
    return column


def validate_operator(operator: str) -> str:
    """Validate operator against allowlist."""
    op_upper = operator.upper().strip()
    if op_upper not in ALLOWED_OPERATORS:
        raise ValueError(f"Invalid operator: {operator}. Allowed operators: {ALLOWED_OPERATORS}")
    return op_upper


def build_search_query(table: str, filters: list, sort_by: str = None,
                       sort_dir: str = 'ASC', limit: int = DEFAULT_LIMIT,
                       offset: int = 0, select_columns: list = None):
    """
    Build a parameterized search query safely.

    Args:
        table: Table name (must be in allowlist)
        filters: List of dicts with 'column', 'operator', 'value' keys
        sort_by: Column to sort by (must be in allowlist)
        sort_dir: Sort direction (ASC or DESC)
        limit: Max rows to return
        offset: Offset for pagination
        select_columns: List of columns to select (None for all allowed columns)

    Returns:
        Tuple of (query_string, params_list)
    """
    # Validate table
    validated_table = validate_table(table)

    # Validate and build SELECT columns
    if select_columns:
        validated_select = []
        for col in select_columns:
            validated_select.append(f"`{validate_column(validated_table, col)}`")
        select_clause = ', '.join(validated_select)
    else:
        # Select all allowed columns for this table
        validated_select = [f"`{col}`" for col in sorted(ALLOWED_COLUMNS[validated_table])]
        select_clause = ', '.join(validated_select)

    # Use backtick-quoted validated table name (already validated against allowlist)
    query = f"SELECT {select_clause} FROM `{validated_table}`"
    params = []

    # Build WHERE clause using parameterized queries
    if filters:
        where_clauses = []
        for f in filters:
            column = validate_column(validated_table, f['column'])
            operator = validate_operator(f['operator'])

            if operator == 'IS NULL':
                where_clauses.append(f"`{column}` IS NULL")
            elif operator == 'IS NOT NULL':
                where_clauses.append(f"`{column}` IS NOT NULL")
            elif operator == 'IN':
                values = f.get('value', [])
                if not isinstance(values, list):
                    raise ValueError("IN operator requires a list of values")
                if not values:
                    raise ValueError("IN operator requires at least one value")
                if len(values) > 100:
                    raise ValueError("IN operator supports at most 100 values")
                placeholders = ', '.join(['%s'] * len(values))
                where_clauses.append(f"`{column}` IN ({placeholders})")
                params.extend(values)
            elif operator == 'LIKE':
                # Escape special LIKE characters in the user value, then add wildcards
                value = f.get('value', '')
                if not isinstance(value, str):
                    raise ValueError("LIKE operator requires a string value")
                # Escape %, _, and \ in the user-provided value
                escaped_value = value.replace('\\', '\\\\').replace('%', '\\%').replace('_', '\\_')
                where_clauses.append(f"`{column}` LIKE %s")
                params.append(f"%{escaped_value}%")
            else:
                where_clauses.append(f"`{column}` {operator} %s")
                params.append(f.get('value'))

        if where_clauses:
            query += " WHERE " + " AND ".join(where_clauses)

    # Build ORDER BY clause
    if sort_by:
        validated_sort_col = validate_column(validated_table, sort_by)
        validated_sort_dir = sort_dir.upper().strip()
        if validated_sort_dir not in ALLOWED_SORT_DIRECTIONS:
            validated_sort_dir = 'ASC'
        query += f" ORDER BY `{validated_sort_col}` {validated_sort_dir}"

    # Build LIMIT/OFFSET with parameterized values
    validated_limit = min(max(int(limit), 1), MAX_LIMIT)
    validated_offset = max(int(offset), 0)
    query += " LIMIT %s OFFSET %s"
    params.extend([validated_limit, validated_offset])

    return query, params


def search_api(request):
    """
    HTTP Cloud Function for flexible search API.

    Expected JSON body:
    {
        "table": "products",
        "filters": [
            {"column": "name", "operator": "LIKE", "value": "widget"},
            {"column": "price", "operator": ">=", "value": 10.00},
            {"column": "status", "operator": "=", "value": "active"},
            {"column": "category_id", "operator": "IN", "value": [1, 2, 3]}
        ],
        "select_columns": ["id", "name", "price"],
        "sort_by": "price",
        "sort_dir": "DESC",
        "limit": 20,
        "offset": 0
    }
    """
    # Set CORS headers for preflight
    if request.method == 'OPTIONS':
        headers = {
            'Access-Control-Allow-Origin': os.environ.get('ALLOWED_ORIGIN', '*'),
            'Access-Control-Allow-Methods': 'POST',
            'Access-Control-Allow-Headers': 'Content-Type, Authorization',
            'Access-Control-Max-Age': '3600',
        }
        return ('', 204, headers)

    response_headers = {
        'Content-Type': 'application/json',
        'Access-Control-Allow-Origin': os.environ.get('ALLOWED_ORIGIN', '*'),
    }

    if request.method != 'POST':
        return (json.dumps({'error': 'Method not allowed. Use POST.'}), 405, response_headers)

    try:
        request_json = request.get_json(silent=True)
        if not request_json:
            return (json.dumps({'error': 'Request body must be valid JSON'}), 400, response_headers)

        table = request_json.get('table')
        if not table:
            return (json.dumps({'error': 'Missing required field: table'}), 400, response_headers)

        filters = request_json.get('filters', [])
        if not isinstance(filters, list):
            return (json.dumps({'error': 'filters must be a list'}), 400, response_headers)

        # Validate each filter has required keys
        for i, f in enumerate(filters):
            if not isinstance(f, dict):
                return (json.dumps({'error': f'Filter at index {i} must be a dict'}), 400, response_headers)
            if 'column' not in f or 'operator' not in f:
                return (json.dumps({'error': f'Filter at index {i} must have "column" and "operator" keys'}),
                        400, response_headers)
            op = f['operator'].upper().strip()
            if op not in ('IS NULL', 'IS NOT NULL') and 'value' not in f:
                return (json.dumps({'error': f'Filter at index {i} requires a "value" key for operator {op}'}),
                        400, response_headers)

        select_columns = request_json.get('select_columns')
        sort_by = request_json.get('sort_by')
        sort_dir = request_json.get('sort_dir', 'ASC')
        limit = request_json.get('limit', DEFAULT_LIMIT)
        offset = request_json.get('offset', 0)

        # Validate numeric types
        try:
            limit = int(limit)
            offset = int(offset)
        except (ValueError, TypeError):
            return (json.dumps({'error': 'limit and offset must be integers'}), 400, response_headers)

        # Build the parameterized query
        query, params = build_search_query(
            table=table,
            filters=filters,
            sort_by=sort_by,
            sort_dir=sort_dir,
            limit=limit,
            offset=offset,
            select_columns=select_columns,
        )

        # Execute query
        connection = get_db_connection()
        try:
            with connection.cursor() as cursor:
                cursor.execute(query, params)
                results = cursor.fetchall()

                # Also get total count for pagination (without LIMIT/OFFSET)
                count_query, count_params = _build_count_query(table, filters)
                cursor.execute(count_query, count_params)
                total_count = cursor.fetchone().get('total', 0)
        finally:
            connection.close()

        # Serialize results (handle datetime, Decimal, etc.)
        serialized_results = _serialize_results(results)

        response_body = {
            'data': serialized_results,
            'pagination': {
                'total': total_count,
                'limit': min(max(int(limit), 1), MAX_LIMIT),
                'offset': max(int(offset), 0),
                'has_more': (max(int(offset), 0) + min(max(int(limit), 1), MAX_LIMIT)) < total_count,
            }
        }

        return (json.dumps(response_body, default=str), 200, response_headers)

    except ValueError as e:
        return (json.dumps({'error': str(e)}), 400, response_headers)
    except pymysql.Error as e:
        # Log the actual error server-side but don't expose details to client
        print(f"Database error: {e}")
        return (json.dumps({'error': 'A database error occurred'}), 500, response_headers)
    except Exception as e:
        print(f"Unexpected error: {e}")
        return (json.dumps({'error': 'An internal error occurred'}), 500, response_headers)


def _build_count_query(table: str, filters: list):
    """Build a COUNT query with the same filters (for pagination)."""
    validated_table = validate_table(table)
    query = f"SELECT COUNT(*) AS total FROM `{validated_table}`"
    params = []

    if filters:
        where_clauses = []
        for f in filters:
            column = validate_column(validated_table, f['column'])
            operator = validate_operator(f['operator'])

            if operator == 'IS NULL':
                where_clauses.append(f"`{column}` IS NULL")
            elif operator == 'IS NOT NULL':
                where_clauses.append(f"`{column}` IS NOT NULL")
            elif operator == 'IN':
                values = f.get('value', [])
                if not isinstance(values, list) or not values:
                    raise ValueError("IN operator requires a non-empty list")
                placeholders = ', '.join(['%s'] * len(values))
                where_clauses.append(f"`{column}` IN ({placeholders})")
                params.extend(values)
            elif operator == 'LIKE':
                value = f.get('value', '')
                escaped_value = value.replace('\\', '\\\\').replace('%', '\\%').replace('_', '\\_')
                where_clauses.append(f"`{column}` LIKE %s")
                params.append(f"%{escaped_value}%")
            else:
                where_clauses.append(f"`{column}` {operator} %s")
                params.append(f.get('value'))

        if where_clauses:
            query += " WHERE " + " AND ".join(where_clauses)

    return query, params


def _serialize_results(results: list) -> list:
    """Serialize query results to JSON-safe types."""
    import decimal
    import datetime

    serialized = []
    for row in results:
        serialized_row = {}
        for key, value in row.items():
            if isinstance(value, decimal.Decimal):
                serialized_row[key] = float(value)
            elif isinstance(value, (datetime.datetime, datetime.date)):
                serialized_row[key] = value.isoformat()
            elif isinstance(value, bytes):
                serialized_row[key] = value.decode('utf-8', errors='replace')
            else:
                serialized_row[key] = value
        serialized.append(serialized_row)
    return serialized